def solve(data: str) -> str:
    parts = list(map(int, data.strip().split()))
    if not parts: return ""
    n = parts[0]; h = parts[1:]
    l,r=0,n-1; lmax=rmax=0; water=0
    while l<=r:
        if h[l] <= h[r]:
            if h[l] >= lmax: lmax = h[l]
            else: water += lmax - h[l]
            l += 1
        else:
            if h[r] >= rmax: rmax = h[r]
            else: water += rmax - h[r]
            r -= 1
    return str(water)


def __main__():
    import sys
    data = sys.stdin.read()
    result = solve(data)
    if result is None:
        return
    sys.stdout.write(str(result))

if __name__ == '__main__':
    __main__()

