import java.io.*;
import java.nio.charset.StandardCharsets;

public class Main {
static class Solution {
    public String solve(String data){
        String[] p = data.trim().split("\\s+");
        if(p.length==0) return "";
        int n = Integer.parseInt(p[0]);
        long[] h = new long[n];
        for(int i=0;i<n;i++) h[i] = Long.parseLong(p[i+1]);
        int l=0, r=n-1; long lmax=0, rmax=0, water=0;
        while(l<=r){
            if(h[l] <= h[r]){
                if(h[l] >= lmax) lmax = h[l]; else water += lmax - h[l];
                l++;
            } else {
                if(h[r] >= rmax) rmax = h[r]; else water += rmax - h[r];
                r--;
            }
        }
        return Long.toString(water);
    }
}


    public static void main(String[] args) throws Exception {
        ByteArrayOutputStream baos = new ByteArrayOutputStream();
        InputStream in = System.in;
        byte[] buf = new byte[8192];
        int n;
        while ((n = in.read(buf)) != -1) {
            baos.write(buf, 0, n);
        }
        String input = baos.toString(StandardCharsets.UTF_8);
        Solution sol = new Solution();
        String output = sol.solve(input);
        if (output != null) {
            System.out.print(output);
        }
    }
}

