#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_INPUT (1 << 20)

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
char* solve(const char* data){
    char* copy = strdup(data);
    const char* delim = " \n\t";
    char* tok = strtok(copy, delim);
    if(!tok){ free(copy); return strdup(""); }
    int n = atoi(tok);
    long long* h = malloc(sizeof(long long)*n);
    for(int i=0;i<n;i++){ tok = strtok(NULL, delim); h[i] = atoll(tok); }
    int l=0, r=n-1; long long lmax=0, rmax=0, water=0;
    while(l<=r){
        if(h[l]<=h[r]){
            if(h[l]>=lmax) lmax=h[l]; else water+=lmax-h[l];
            l++;
        } else {
            if(h[r]>=rmax) rmax=h[r]; else water+=rmax-h[r];
            r--;
        }
    }
    free(copy); free(h);
    char buf[32]; sprintf(buf, "%lld", water);
    return strdup(buf);
}


int main() {
    char *input = (char *)malloc(MAX_INPUT);
    if (!input) return 1;
    size_t len = fread(input, 1, MAX_INPUT - 1, stdin);
    input[len] = '\0';
    char *output = solve(input);
    if (output) {
        fputs(output, stdout);
        free(output);
    }
    free(input);
    return 0;
}
